use std::error::Error;
use std::fmt::{self, Write};

#[derive(Debug)]
struct IoError { 
    message: String
}
impl fmt::Display for IoError {
    fn fmt(&self, f: &mut fmt::Formatter) -> fmt::Result {
        write!(f, "I/O Failure: {}", self.message)
    }
}
impl Error for IoError {}

type Result<T> = std::result::Result<T, Box<dyn Error + Send + Sync>>;

struct Peripheral<const ID: usize> {
    base_address: u32,
}

impl<const ID: usize> Peripheral<ID> {
    fn new(base_addr: u32) -> Self {
        Peripheral { base_address: base_addr }
    }

    fn write_register(&self, offset: u32, value: u32) -> Result<()> {
        println!("Writing 0x{:X} to peripheral {} at address 0x{:X}", value, ID, self.base_address + offset);
        Ok(())
    }
}

struct Bootloader {
    gpio: Peripheral<10>,
    uart: Peripheral<20>,
}

impl Bootloader {
    fn new() -> Self {
        Bootloader {
            gpio: Peripheral::new(0x4000_0000),
            uart: Peripheral::new(0x4001_0000),
        }
    }

    fn initialize(&self) -> Result<()> {
        println!("Initializing hardware peripherals...");
        let _ = self.gpio.write_register(0x00, 0xAAAA)?; 
        self.uart.write_register(0x04, 1)?; 
        Ok(()) 
    }
}

fn main() -> Result<()> {
    let bl = Bootloader::new();
    bl.initialize()?;
    println!("Bootloader setup complete.");
    Ok(())
}
